<?php
namespace App\Http\Controllers\Admin; use App\Http\Controllers\Controller; use App\Http\Requests\Admin\CompanySettingRequest; use App\Models\{CompanySetting,Currency,Language}; use App\Services\Admin\ActivityLogger;
class CompanySettingController extends Controller { public function edit(){return view('admin.settings.company',['setting'=>CompanySetting::first()??new CompanySetting(['company_name'=>'TravelHub ERP']),'currencies'=>Currency::all(),'languages'=>Language::all()]);} public function update(CompanySettingRequest $r, ActivityLogger $l){$data=$r->validated(); if($r->hasFile('logo')) $data['logo']=$r->file('logo')->store('company','public'); $setting=CompanySetting::first(); $setting?$setting->update($data):$setting=CompanySetting::create($data); $l->log('updated','Updated company settings',$setting); return back();} }
